WITH ftp AS (
  SELECT COALESCE(
    (SELECT value::numeric FROM sync_state WHERE key = 'configured_ftp' AND value::numeric > 0),
    (SELECT ROUND(MAX(avg_20min) * 0.95) FROM (
      SELECT AVG(s.power) OVER (PARTITION BY s.activity_id ORDER BY s.time_offset RANGE BETWEEN 1199 PRECEDING AND CURRENT ROW) AS avg_20min
      FROM activity_streams s
      JOIN activities a ON a.id = s.activity_id
      WHERE a.date >= CURRENT_DATE - interval '90 days'
        AND s.power IS NOT NULL AND s.power > 0
    ) sub WHERE avg_20min IS NOT NULL),
    (SELECT percentile_cont(0.95) WITHIN GROUP (ORDER BY avg_power) FROM activities WHERE avg_power IS NOT NULL AND avg_power > 0)
  ) AS ftp_val
), data AS (SELECT CASE WHEN s.power < ftp.ftp_val * 0.55 THEN 'z1' WHEN s.power < ftp.ftp_val * 0.75 THEN 'z2' WHEN s.power < ftp.ftp_val * 0.90 THEN 'z3' WHEN s.power < ftp.ftp_val * 1.05 THEN 'z4' WHEN s.power < ftp.ftp_val * 1.20 THEN 'z5' ELSE 'z6' END AS z FROM activity_streams s, ftp WHERE s.activity_id = ${activity_id} AND s.power IS NOT NULL AND s.power > 0) SELECT 'Power' AS "x", COALESCE((SELECT COUNT(*) FROM data WHERE z='z1'), 0) AS "Z1 Recovery", COALESCE((SELECT COUNT(*) FROM data WHERE z='z2'), 0) AS "Z2 Endurance", COALESCE((SELECT COUNT(*) FROM data WHERE z='z3'), 0) AS "Z3 Tempo", COALESCE((SELECT COUNT(*) FROM data WHERE z='z4'), 0) AS "Z4 Threshold", COALESCE((SELECT COUNT(*) FROM data WHERE z='z5'), 0) AS "Z5 VO2max", COALESCE((SELECT COUNT(*) FROM data WHERE z='z6'), 0) AS "Z6 Anaerobic";

WITH ftp AS (
  SELECT COALESCE(
    (SELECT value::numeric FROM sync_state WHERE key = 'configured_ftp' AND value::numeric > 0),
    (SELECT ROUND(MAX(avg_20min) * 0.95) FROM (
      SELECT AVG(s.power) OVER (PARTITION BY s.activity_id ORDER BY s.time_offset RANGE BETWEEN 1199 PRECEDING AND CURRENT ROW) AS avg_20min
      FROM activity_streams s
      JOIN activities a ON a.id = s.activity_id
      WHERE a.date >= CURRENT_DATE - interval '90 days'
        AND s.power IS NOT NULL AND s.power > 0
    ) sub WHERE avg_20min IS NOT NULL),
    (SELECT percentile_cont(0.95) WITHIN GROUP (ORDER BY avg_power) FROM activities WHERE avg_power IS NOT NULL AND avg_power > 0)
  ) AS ftp_val
), rolling AS (SELECT AVG(power) OVER (ORDER BY time_offset RANGE BETWEEN 29 PRECEDING AND CURRENT ROW) AS rolling_30s FROM activity_streams WHERE activity_id = ${activity_id} AND power IS NOT NULL AND power > 0) SELECT ROUND((POWER(AVG(POWER(rolling_30s, 4)), 0.25) / ftp.ftp_val)::numeric, 2) AS "IF" FROM rolling, ftp WHERE rolling_30s IS NOT NULL GROUP BY ftp.ftp_val;

WITH ftp AS (
  SELECT COALESCE(
    (SELECT value::numeric FROM sync_state WHERE key = 'configured_ftp' AND value::numeric > 0),
    (SELECT ROUND(MAX(avg_20min) * 0.95) FROM (
      SELECT AVG(s.power) OVER (PARTITION BY s.activity_id ORDER BY s.time_offset RANGE BETWEEN 1199 PRECEDING AND CURRENT ROW) AS avg_20min
      FROM activity_streams s
      JOIN activities a ON a.id = s.activity_id
      WHERE a.date >= CURRENT_DATE - interval '90 days'
        AND s.power IS NOT NULL AND s.power > 0
    ) sub WHERE avg_20min IS NOT NULL),
    (SELECT percentile_cont(0.95) WITHIN GROUP (ORDER BY avg_power) FROM activities WHERE avg_power IS NOT NULL AND avg_power > 0)
  ) AS ftp_val
), buckets AS (SELECT FLOOR(power / 10) * 10 AS bucket, COUNT(*) / 60.0 AS mins, CASE WHEN power < ftp.ftp_val * 0.55 THEN 'Z1 Recovery' WHEN power < ftp.ftp_val * 0.75 THEN 'Z2 Endurance' WHEN power < ftp.ftp_val * 0.90 THEN 'Z3 Tempo' WHEN power < ftp.ftp_val * 1.05 THEN 'Z4 Threshold' WHEN power < ftp.ftp_val * 1.20 THEN 'Z5 VO2max' ELSE 'Z6 Anaerobic' END AS zone FROM activity_streams, ftp WHERE activity_id = ${activity_id} AND power IS NOT NULL AND power > 0 GROUP BY bucket, zone) SELECT bucket::int AS "Power (W)", COALESCE(SUM(mins) FILTER (WHERE zone = 'Z1 Recovery'), 0) AS "Z1 Recovery", COALESCE(SUM(mins) FILTER (WHERE zone = 'Z2 Endurance'), 0) AS "Z2 Endurance", COALESCE(SUM(mins) FILTER (WHERE zone = 'Z3 Tempo'), 0) AS "Z3 Tempo", COALESCE(SUM(mins) FILTER (WHERE zone = 'Z4 Threshold'), 0) AS "Z4 Threshold", COALESCE(SUM(mins) FILTER (WHERE zone = 'Z5 VO2max'), 0) AS "Z5 VO2max", COALESCE(SUM(mins) FILTER (WHERE zone = 'Z6 Anaerobic'), 0) AS "Z6 Anaerobic" FROM buckets GROUP BY bucket ORDER BY bucket;
